import{_ as t}from"./chunks/微笑狼的公开仓库.gGdYP2E_.js";import{_ as e,o as d,c as s,a2 as c}from"./chunks/framework.DnrXFDHb.js";const b=JSON.parse('{"title":"自動打標籤使用說明","description":"","frontmatter":{},"headers":[],"relativePath":"zh-TW/Other/auto-tagging.md","filePath":"zh-TW/Other/auto-tagging.md","lastUpdated":1781962217000}'),i={name:"zh-TW/Other/auto-tagging.md"};function p(o,a,l,n,r,h){return d(),s("div",null,[...a[0]||(a[0]=[c('<h1 id="自動打標籤使用說明" tabindex="-1">自動打標籤使用說明 <a class="header-anchor" href="#自動打標籤使用說明" aria-label="Permalink to &quot;自動打標籤使用說明&quot;">​</a></h1><p>自動打標籤在：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>系統設定 -&gt; 其他設定 -&gt; 自動打標籤</span></span></code></pre></div><p>這個功能會替圖片自動產生標籤，方便之後搜尋、隨機圖篩選、訪客圖庫篩選，以及年齡分級存取控制。</p><h2 id="自動打標籤能做什麼" tabindex="-1">自動打標籤能做什麼 <a class="header-anchor" href="#自動打標籤能做什麼" aria-label="Permalink to &quot;自動打標籤能做什麼&quot;">​</a></h2><table tabindex="0"><thead><tr><th>功能</th><th>說明</th></tr></thead><tbody><tr><td>產生內容標籤</td><td>例如人物、場景、物件、畫風等標籤</td></tr><tr><td>產生角色標籤</td><td>對動漫圖、插畫裡的角色特別有用</td></tr><tr><td>補方向標籤</td><td>自動補 <code>landscape</code>、<code>portrait</code>、<code>square</code></td></tr><tr><td>補圖片分級</td><td>儲存 <code>G/S/Q/E</code> 分級結果</td></tr><tr><td>上傳時自動打標</td><td>開啟後，新上傳圖片會自動進入打標流程</td></tr><tr><td>批次打標</td><td>可以替全部或指定資料夾裡的舊圖片補標籤</td></tr></tbody></table><h2 id="需要先準備什麼" tabindex="-1">需要先準備什麼 <a class="header-anchor" href="#需要先準備什麼" aria-label="Permalink to &quot;需要先準備什麼&quot;">​</a></h2><p>你需要至少一個可以存取的 Hugging Face Space。</p><p>建議把 SmilingWolf 的 <code>wd-tagger</code> 複製到自己的 Hugging Face 帳號使用：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://huggingface.co/spaces/SmilingWolf/wd-tagger</span></span></code></pre></div><p>也可以先臨時使用公開 Space，但公開 Space 很多人一起用，容易排隊、變慢或暫時不可用。自己的 Space 比較穩，也比較適合長期自動打標。</p><h2 id="複製-smilingwolf-的-space" tabindex="-1">複製 SmilingWolf 的 Space <a class="header-anchor" href="#複製-smilingwolf-的-space" aria-label="Permalink to &quot;複製 SmilingWolf 的 Space&quot;">​</a></h2><ol><li>登入 Hugging Face。</li><li>打開 <code>https://huggingface.co/spaces/SmilingWolf/wd-tagger</code>。</li></ol><p><img src="'+t+`" alt="SmilingWolf 公開 Space" loading="lazy"></p><ol start="3"><li>點右上角三個點。</li><li>選 <code>Duplicate this Space</code>。</li><li>Space 名稱可保持預設，也可以改成自己喜歡的名字，例如 <code>wd-tagger</code>。</li><li>可見性建議選 <code>Public</code>，比較方便 ImgBed 呼叫。</li><li>硬體先用預設免費配置即可，排隊明顯時再考慮升級。</li><li>建立後等待 Space 建置完成。</li></ol><p>建置完成後，進入你自己的 Space 頁面。網址通常像：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://huggingface.co/spaces/你的使用者名稱/wd-tagger</span></span></code></pre></div><p>直接複製瀏覽器網址，貼到 ImgBed 的 <code>Space URLs</code>。</p><h2 id="多個-space-urls-怎麼填" tabindex="-1">多個 Space URLs 怎麼填 <a class="header-anchor" href="#多個-space-urls-怎麼填" aria-label="Permalink to &quot;多個 Space URLs 怎麼填&quot;">​</a></h2><p><code>Space URLs</code> 一行填一個。</p><table tabindex="0"><thead><tr><th>填寫內容</th><th>說明</th></tr></thead><tbody><tr><td><code>https://huggingface.co/spaces/SmilingWolf/wd-tagger</code></td><td>SmilingWolf 公開 Space，適合臨時測試</td></tr><tr><td><code>https://huggingface.co/spaces/lintonxue00/wd-tagger</code></td><td>直接複製 Space 頁面連結</td></tr><tr><td><code>https://huggingface.co/spaces/你的使用者名稱/wd-tagger</code></td><td>你自己複製後的 Space</td></tr></tbody></table><p>可以填多個地址。系統會同時使用多個 Space 處理圖片，速度會更快；其中一個暫時不可用時，其他 Space 仍可繼續處理。</p><h2 id="頁面選項怎麼填" tabindex="-1">頁面選項怎麼填 <a class="header-anchor" href="#頁面選項怎麼填" aria-label="Permalink to &quot;頁面選項怎麼填&quot;">​</a></h2><table tabindex="0"><thead><tr><th>選項</th><th>建議</th></tr></thead><tbody><tr><td><code>Space URLs</code></td><td>填你準備好的 Space 地址，建議至少 1 個</td></tr><tr><td>目標資料夾</td><td>不選就是全部資料夾；只想處理某個目錄時再選</td></tr><tr><td>辨識模型</td><td>預設 <code>wd-swinv2-tagger-v3</code> 即可</td></tr><tr><td>通用標籤閾值</td><td>預設值適合大多數圖片，越低標籤越多，越高標籤越少</td></tr><tr><td>角色標籤閾值</td><td>預設值偏穩，適合避免角色誤判</td></tr><tr><td>使用 <code>MCut</code></td><td>不確定時先關閉，需要模型自動判斷標籤數量時再開</td></tr><tr><td>上傳時自動打標</td><td>想讓新圖自動有標籤就開啟</td></tr><tr><td>開始打標籤</td><td>手動替舊圖片批次補標籤</td></tr></tbody></table><h2 id="推薦初始設定" tabindex="-1">推薦初始設定 <a class="header-anchor" href="#推薦初始設定" aria-label="Permalink to &quot;推薦初始設定&quot;">​</a></h2><table tabindex="0"><thead><tr><th>選項</th><th>推薦值</th></tr></thead><tbody><tr><td>辨識模型</td><td><code>wd-swinv2-tagger-v3</code></td></tr><tr><td>通用標籤閾值</td><td><code>0.35</code></td></tr><tr><td>角色標籤閾值</td><td><code>0.85</code></td></tr><tr><td><code>MCut</code></td><td>先關閉</td></tr><tr><td>上傳時自動打標</td><td>依需求開啟</td></tr></tbody></table><p>如果標籤太多，可以把通用標籤閾值調高一點；標籤太少，就調低一點。</p><h2 id="批次打標怎麼用" tabindex="-1">批次打標怎麼用 <a class="header-anchor" href="#批次打標怎麼用" aria-label="Permalink to &quot;批次打標怎麼用&quot;">​</a></h2><ol><li>先填好 <code>Space URLs</code>。</li><li>選擇目標資料夾。</li><li>點開始打標籤。</li><li>等進度完成。</li></ol><p>目標資料夾留空時會處理全部資料夾。</p><p>批次打標適合處理舊圖片。新圖片建議開啟上傳時自動打標，之後就不用每次手動跑。</p><h2 id="上傳時自動打標" tabindex="-1">上傳時自動打標 <a class="header-anchor" href="#上傳時自動打標" aria-label="Permalink to &quot;上傳時自動打標&quot;">​</a></h2><p>開啟後，新上傳圖片會自動呼叫你填的 <code>Space URLs</code>。</p><p>如果 Space 正在排隊，上傳本身會先完成，打標會在後面繼續處理。</p><h2 id="哪些圖片會被處理" tabindex="-1">哪些圖片會被處理 <a class="header-anchor" href="#哪些圖片會被處理" aria-label="Permalink to &quot;哪些圖片會被處理&quot;">​</a></h2><p>自動打標主要處理圖片檔。</p><p>已經有完整標籤、方向、分級、寬高資訊的圖片會跳過，不會重複浪費 Space 呼叫。</p><p>缺什麼就補什麼。例如只缺方向標籤時，系統會盡量只補方向；缺內容標籤時，才會呼叫 Space 產生內容標籤。</p><h2 id="常見問題" tabindex="-1">常見問題 <a class="header-anchor" href="#常見問題" aria-label="Permalink to &quot;常見問題&quot;">​</a></h2><h3 id="為什麼建議複製自己的-space" tabindex="-1">為什麼建議複製自己的 Space？ <a class="header-anchor" href="#為什麼建議複製自己的-space" aria-label="Permalink to &quot;為什麼建議複製自己的 Space？&quot;">​</a></h3><p>公開 Space 是大家一起用的，別人也在排隊。複製到自己的帳號後，主要供你的 ImgBed 使用，速度和穩定性通常更好。</p><h3 id="space-一直啟動中怎麼辦" tabindex="-1">Space 一直啟動中怎麼辦？ <a class="header-anchor" href="#space-一直啟動中怎麼辦" aria-label="Permalink to &quot;Space 一直啟動中怎麼辦？&quot;">​</a></h3><p>第一次打開或長時間沒人用時，Space 可能需要啟動一下。可以先打開你的 Space 頁面，等它能正常辨識圖片後，再回 ImgBed 開始打標。</p><h3 id="space-地址怎麼複製" tabindex="-1">Space 地址怎麼複製？ <a class="header-anchor" href="#space-地址怎麼複製" aria-label="Permalink to &quot;Space 地址怎麼複製？&quot;">​</a></h3><p>打開你的 Hugging Face Space 頁面，直接複製瀏覽器網址即可。</p><h3 id="可以填多個-space-嗎" tabindex="-1">可以填多個 Space 嗎？ <a class="header-anchor" href="#可以填多個-space-嗎" aria-label="Permalink to &quot;可以填多個 Space 嗎？&quot;">​</a></h3><p>可以。每行一個 Space 地址。圖片很多時，多個 Space 會一起處理。</p><h3 id="標籤語言為什麼是英文" tabindex="-1">標籤語言為什麼是英文？ <a class="header-anchor" href="#標籤語言為什麼是英文" aria-label="Permalink to &quot;標籤語言為什麼是英文？&quot;">​</a></h3><p>SmilingWolf 模型輸出的是英文標籤，這是正常現象。這些標籤主要用於搜尋、篩選、隨機圖 API 和公開圖庫篩選。</p><h3 id="分級標籤有什麼用" tabindex="-1">分級標籤有什麼用？ <a class="header-anchor" href="#分級標籤有什麼用" aria-label="Permalink to &quot;分級標籤有什麼用？&quot;">​</a></h3><p>分級結果會配合安全設定裡的存取模式使用。例如訪客模式限制年齡分級後，公開瀏覽和隨機圖會依規則過濾圖片。</p><h2 id="快速流程" tabindex="-1">快速流程 <a class="header-anchor" href="#快速流程" aria-label="Permalink to &quot;快速流程&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>登入 Hugging Face</span></span>
<span class="line"><span>-&gt; 打開 SmilingWolf/wd-tagger</span></span>
<span class="line"><span>-&gt; Duplicate this Space</span></span>
<span class="line"><span>-&gt; 等 Space 建置完成</span></span>
<span class="line"><span>-&gt; 複製自己的 Space 地址</span></span>
<span class="line"><span>-&gt; 回 ImgBed 填 Space URLs</span></span>
<span class="line"><span>-&gt; 選模型和閾值</span></span>
<span class="line"><span>-&gt; 開始打標或開啟上傳時自動打標</span></span></code></pre></div>`,53)])])}const S=e(i,[["render",p]]);export{b as __pageData,S as default};
